namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers", Ingredients = "Baguette
Tomatoes
Fresh basil
Garlic
Olive oil
Balsamic vinegar", Steps = "1. Slice and toast the baguette
2. Dice tomatoes and mix with chopped basil, minced garlic, and olive oil
3. Spoon mixture onto toasted bread
4. Drizzle with balsamic vinegar and serve" },
            new() { Id = 2, Title = "Spinach Artichoke Dip", Category = "Appetizers", CategorySlug = "appetizers", Ingredients = "Frozen spinach
Artichoke hearts
Cream cheese
Sour cream
Parmesan
Garlic", Steps = "1. Thaw and drain spinach
2. Mix cream cheese, sour cream, and parmesan
3. Fold in spinach and chopped artichoke hearts
4. Bake at 350°F for 25 minutes until bubbly" },
            new() { Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses", Ingredients = "Spaghetti
Pancetta
Eggs
Parmesan cheese
Black pepper
Salt", Steps = "1. Cook spaghetti until al dente
2. Fry pancetta until crispy
3. Whisk eggs with grated parmesan and pepper
4. Toss hot pasta with pancetta, then stir in egg mixture off heat
5. Serve immediately with extra parmesan" },
            new() { Id = 4, Title = "Chicken Tikka Masala", Category = "Main Courses", CategorySlug = "main-courses", Ingredients = "Chicken breast
Yogurt
Tomato sauce
Heavy cream
Garam masala
Cumin
Turmeric
Garlic
Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours
2. Grill or broil chicken until charred
3. Sauté garlic and ginger, add tomato sauce and spices
4. Simmer sauce, add cream
5. Add chicken pieces and simmer 10 minutes
6. Serve with rice or naan" },
            new() { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts", Ingredients = "Dark chocolate
Butter
Eggs
Sugar
Flour
Vanilla extract", Steps = "1. Melt chocolate and butter together
2. Whisk eggs and sugar until fluffy
3. Fold chocolate mixture into eggs, add flour and vanilla
4. Pour into greased ramekins
5. Bake at 425°F for 12-14 minutes
6. Invert onto plates and serve immediately" },
            new() { Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts", Ingredients = "Ladyfingers
Mascarpone
Eggs
Sugar
Espresso
Cocoa powder
Kahlua (optional)", Steps = "1. Brew espresso and let cool
2. Separate eggs; whisk yolks with sugar until pale
3. Fold in mascarpone
4. Whip egg whites to stiff peaks and fold into mascarpone mixture
5. Dip ladyfingers briefly in espresso
6. Layer ladyfingers and cream in a dish
7. Refrigerate 4+ hours, dust with cocoa before serving" },
        };
    }

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public List<Recipe> GetAll()
    {
        return _recipes.ToList();
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
            recipe.RatingCount++;
            recipe.AverageRating = totalStars / recipe.RatingCount;
        }
    }
}

