arguments.file_text:
@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeShare</PageTitle>

<h1>Browse Recipes</h1>

@if (string.IsNullOrEmpty(CategorySlug))
{
    <p class="lead">Select a category to browse recipes.</p>
    <div class="list-group">
        <a href="recipes/appetizers" class="list-group-item list-group-item-action">🥗 Appetizers</a>
        <a href="recipes/main-courses" class="list-group-item list-group-item-action">🍝 Main Courses</a>
        <a href="recipes/desserts" class="list-group-item list-group-item-action">🍰 Desserts</a>
    </div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item active">@CategoryDisplay</li>
        </ol>
    </nav>

    @if (Recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            @if (recipe.RatingCount > 0)
                            {
                                <p class="card-text text-muted">
                                    ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                                </p>
                            }
                            <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> Recipes { get; set; } = new();
    private string CategoryDisplay => CategorySlug?.Replace("-", " ") ?? string.Empty;

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(CategorySlug))
        {
            Recipes = RecipeService.GetByCategory(CategorySlug);
        }
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item"><a href="recipes/@Recipe.CategorySlug">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <StarRating RecipeId="Recipe.Id" CurrentRating="Recipe.AverageRating" RatingCount="Recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group list-group-flush mb-3">
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' || (text.Length > 3 && text[2] == '.'))
            {
                text = text[(text.IndexOf('.') + 1)..].TrimStart();
            }
            <li class="list-group-item">@text</li>
        }
    </ol>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-sm @(star <= displayRating ? "btn-warning" : "btn-outline-secondary")"
                @onclick="() => SubmitRating(star)"
                @onmouseover="() => displayRating = star"
                @onmouseout="() => displayRating = userRating > 0 ? userRating : (int)Math.Round(CurrentRating)"
                title="@star star(s)"
                disabled="@hasRated">
            ★
        </button>
    }
    @if (hasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
    <div class="text-muted small mt-1">
        @if (RatingCount > 0)
        {
            <span>Average: @CurrentRating.ToString("F1") ⭐ (@RatingCount ratings)</span>
        }
        else
        {
            <span>No ratings yet — be the first!</span>
        }
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int displayRating;
    private int userRating;
    private bool hasRated;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void SubmitRating(int stars)
    {
        if (hasRated) return;
        RecipeService.AddRating(RecipeId, stars);
        userRating = stars;
        displayRating = stars;
        hasRated = true;

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@model.Title</strong>" has been added. <a href="recipe/@newRecipeId">View it here</a>.</p>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 apples, sliced" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.Steps" placeholder="1. Preheat oven to 375°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;
    private int newRecipeId;

    private void HandleSubmit()
    {
        var categorySlug = model.Category.ToLower().Replace(" ", "-");
        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            CategorySlug = categorySlug,
            Ingredients = model.Ingredients,
            Steps = model.Steps
        };
        RecipeService.AddRecipe(recipe);
        newRecipeId = recipe.Id;
        submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

